import { useState, useEffect } from 'react';
import usePageTitle from '../hooks/usePageTitle';
import s from './ApiKeysPage.module.css';

const STORAGE_KEY = 'aura_api_keys';

const SCOPE_OPTIONS = [
  { value: 'read', label: 'Read-only', description: 'View data, no modifications' },
  { value: 'read-write', label: 'Read-write', description: 'Full API access including trade signals' },
];

const RATE_LIMITS = {
  read: '2000 req/min',
  'read-write': '1000 req/min',
};

function loadKeys() {
  try {
    const raw = localStorage.getItem(STORAGE_KEY);
    if (raw) return JSON.parse(raw);
  } catch { /* ignore */ }
  return [];
}

function saveKeys(keys) {
  try { localStorage.setItem(STORAGE_KEY, JSON.stringify(keys)); } catch { /* ignore */ }
}

function generateKeyString() {
  const chars = 'abcdefghijklmnopqrstuvwxyz0123456789';
  let result = 'aura_';
  for (let i = 0; i < 32; i++) result += chars[Math.floor(Math.random() * chars.length)];
  return result;
}

function StatusBadge({ status }) {
  const colorMap = {
    active: 'var(--color-green, #22C55E)',
    revoked: 'var(--color-red, #EF4444)',
    expired: 'var(--color-amber, #F59E0B)',
  };
  const color = colorMap[status] || 'var(--color-text-secondary, #90A3AF)';
  return (
    <span className={s.statusBadge} style={{ background: color }}>
      {status}
    </span>
  );
}

function ScopeBadge({ scope }) {
  return (
    <span className={s.scopeBadge} style={{
      background: scope === 'read-write'
        ? 'rgba(96, 165, 250, 0.12)'
        : 'rgba(34, 197, 94, 0.10)',
      color: scope === 'read-write'
        ? 'var(--color-blue, #60A5FA)'
        : 'var(--color-green, #22C55E)',
      border: `1px solid ${scope === 'read-write' ? 'rgba(96,165,250,0.25)' : 'rgba(34,197,94,0.25)'}`,
    }}>
      {scope === 'read-write' ? 'read-write' : 'read-only'}
    </span>
  );
}

function CopyButton({ text }) {
  const [copied, setCopied] = useState(false);
  const handleCopy = () => {
    navigator.clipboard.writeText(text).then(() => {
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    }).catch(() => {
      // Fallback for non-HTTPS
      const el = document.createElement('textarea');
      el.value = text;
      document.body.appendChild(el);
      el.select();
      document.execCommand('copy');
      document.body.removeChild(el);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    });
  };
  return (
    <button onClick={handleCopy} className={s.copyBtn} title="Copy to clipboard">
      {copied ? '✓ Copied' : 'Copy'}
    </button>
  );
}

function RevokeConfirmModal({ keyName, onConfirm, onCancel }) {
  return (
    <div className={s.modalOverlay} onClick={onCancel}>
      <div className={s.modal} onClick={e => e.stopPropagation()}>
        <div className={s.modalTitle}>Revoke API Key</div>
        <p className={s.modalBody}>
          Are you sure you want to revoke <strong>{keyName}</strong>?
          This cannot be undone. Any applications using this key will immediately lose access.
        </p>
        <div className={s.modalActions}>
          <button onClick={onCancel} className={s.cancelBtn}>Cancel</button>
          <button onClick={onConfirm} className={s.revokeConfirmBtn}>Revoke Key</button>
        </div>
      </div>
    </div>
  );
}

export default function ApiKeysPage() {
  usePageTitle('API Keys');
  const [keys, setKeys] = useState(loadKeys);
  const [showForm, setShowForm] = useState(false);
  const [newKeyName, setNewKeyName] = useState('');
  const [newKeyScope, setNewKeyScope] = useState('read');
  const [justCreated, setJustCreated] = useState(null); // { id, key } — shown once
  const [revokeTarget, setRevokeTarget] = useState(null); // key object

  const handleGenerate = () => {
    if (!newKeyName.trim()) return;
    const keyStr = generateKeyString();
    const newKey = {
      id: Date.now(),
      name: newKeyName.trim(),
      key: keyStr,
      created: new Date().toISOString().slice(0, 10),
      lastUsed: 'Never',
      status: 'active',
      scope: newKeyScope,
    };
    setKeys(prev => {
      const updated = [...prev, newKey];
      saveKeys(updated);
      return updated;
    });
    setJustCreated({ id: newKey.id, key: keyStr });
    setNewKeyName('');
    setNewKeyScope('read');
    setShowForm(false);
  };

  const handleRevoke = (id) => {
    setKeys(prev => {
      const updated = prev.map(k => k.id === id ? { ...k, status: 'revoked' } : k);
      saveKeys(updated);
      return updated;
    });
    setRevokeTarget(null);
  };

  return (
    <div className={s.page}>
      <h1 className={s.title}>API Keys</h1>
      <p className={s.subtitle}>
        Manage personal API keys for programmatic access to Aura Alpha
      </p>

      {/* Warning Banner */}
      <div
        className={s.warningBanner}
        style={{
          background: 'color-mix(in srgb, var(--color-amber, #F59E0B) 7%, transparent)',
          border: '1px solid color-mix(in srgb, var(--color-amber, #F59E0B) 27%, transparent)',
          color: 'var(--color-amber, #F59E0B)',
        }}
      >
        <span className={s.warningIcon}>&#9888;</span>
        <span>
          API keys grant access to your account. Keep them secret — each key is shown <strong>only once</strong> at creation.
        </span>
      </div>

      {/* New Key Banner (shown once after creation) */}
      {justCreated && (
        <div className={s.newKeyBanner}>
          <div className={s.newKeyHeader}>
            <span className={s.newKeyTitle}>New key created — copy it now</span>
            <button onClick={() => setJustCreated(null)} className={s.dismissBtn}>Dismiss</button>
          </div>
          <div className={s.newKeyRow}>
            <code className={s.newKeyValue}>{justCreated.key}</code>
            <CopyButton text={justCreated.key} />
          </div>
          <div className={s.newKeyWarning}>This key will not be shown again.</div>
        </div>
      )}

      {/* Keys Table */}
      <div className={s.tableContainer}>
        <table className={s.table}>
          <thead>
            <tr className={s.tableHeaderRow}>
              {['Name', 'Key', 'Scope', 'Created', 'Last Used', 'Rate Limit', 'Status', 'Actions'].map(h => (
                <th key={h} className={s.tableHeader}>
                  {h}
                </th>
              ))}
            </tr>
          </thead>
          <tbody>
            {keys.map((k) => (
              <tr key={k.id} className={s.tableRow}>
                <td className={s.cellName}>{k.name}</td>
                <td className={s.cellKey}>
                  <div className={s.keyCell}>
                    <span className={s.keyMasked}>
                      {k.status === 'active'
                        ? k.key.slice(0, 10) + '••••••••••••••••••••••'
                        : k.key.slice(0, 10) + '••••••••••••••••••••••'}
                    </span>
                    {k.status === 'active' && (
                      <CopyButton text={k.key} />
                    )}
                  </div>
                </td>
                <td className={s.tableCell}>
                  <ScopeBadge scope={k.scope || 'read'} />
                </td>
                <td className={s.cellSecondary}>{k.created}</td>
                <td className={s.cellSecondary}>{k.lastUsed}</td>
                <td className={s.cellSecondary}>{RATE_LIMITS[k.scope || 'read']}</td>
                <td className={s.tableCell}>
                  <StatusBadge status={k.status} />
                </td>
                <td className={s.tableCell}>
                  {k.status === 'active' && (
                    <button
                      onClick={() => setRevokeTarget(k)}
                      className={s.revokeBtn}
                    >
                      Revoke
                    </button>
                  )}
                </td>
              </tr>
            ))}
            {keys.length === 0 && (
              <tr>
                <td colSpan={8} className={s.emptyRow}>
                  No API keys configured
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Generate New Key */}
      {showForm ? (
        <div className={s.formContainer}>
          <input
            type="text"
            placeholder="Key name (e.g., CI Pipeline)"
            value={newKeyName}
            onChange={e => setNewKeyName(e.target.value)}
            onKeyDown={e => e.key === 'Enter' && handleGenerate()}
            className={s.formInput}
            autoFocus
          />
          <div className={s.scopeSelect}>
            {SCOPE_OPTIONS.map(opt => (
              <label key={opt.value} className={s.scopeOption}>
                <input
                  type="radio"
                  name="scope"
                  value={opt.value}
                  checked={newKeyScope === opt.value}
                  onChange={() => setNewKeyScope(opt.value)}
                  style={{ accentColor: 'var(--color-blue, #60A5FA)' }}
                />
                <span className={s.scopeOptionLabel}>
                  <span className={s.scopeOptionName}>{opt.label}</span>
                  <span className={s.scopeOptionDesc}>{opt.description}</span>
                </span>
              </label>
            ))}
          </div>
          <div className={s.formActions}>
            <button onClick={handleGenerate} className={s.createBtn}>
              Generate Key
            </button>
            <button
              onClick={() => { setShowForm(false); setNewKeyName(''); setNewKeyScope('read'); }}
              className={s.cancelBtn}
            >
              Cancel
            </button>
          </div>
        </div>
      ) : (
        <button onClick={() => setShowForm(true)} className={s.generateBtn}>
          + Create New Key
        </button>
      )}

      {/* Rate Limits info */}
      <div className={s.rateLimitsSection}>
        <div className={s.rateLimitItem}>
          <div className={s.rateDot} style={{ background: 'var(--color-green, #22C55E)' }} />
          <span>Read-only keys: <span className={s.rateValue}>2000 req/min</span></span>
        </div>
        <div className={s.rateLimitItem}>
          <div className={s.rateDot} style={{ background: 'var(--color-blue, #60A5FA)' }} />
          <span>Read-write keys: <span className={s.rateValue}>1000 req/min</span></span>
        </div>
      </div>

      {/* Revoke confirmation modal */}
      {revokeTarget && (
        <RevokeConfirmModal
          keyName={revokeTarget.name}
          onConfirm={() => handleRevoke(revokeTarget.id)}
          onCancel={() => setRevokeTarget(null)}
        />
      )}
    </div>
  );
}
